import { getSVGsymbol, getSegmentsForSymbol } from '../utils/svg-symbols';
import { defined } from '../utils/zcutils';
import { mathAbs } from '../core/zc-constants';

export function whiskerSize(d, y, quartileIdx, whiskerIdx, minmaxId, yidx) {
    if (defined(yidx)) {
        return mathAbs(y(d[yidx][1]) - y(d[yidx][0]));
    }
    return y(d[whiskerIdx][minmaxId]) - y(d[quartileIdx][minmaxId]);
}

// export function whiskers(type1, size1, type2, size2) {
