// }

export function whiskers(symbols) {
    let lastPos = symbols.length - 1,
        whiskerSymbol = '';
    symbols.map((d, i) => {
        if (i == lastPos) {
            whiskerSymbol += `${getSVGsymbol(d[0])(d[1])}`;
        } else {
            whiskerSymbol += `${getSVGsymbol(d[0])(d[1])} Z `; //d[0] = type of the symbol, d[1] = size of the symbol
        }
    });
    return whiskerSymbol;
}

export function whiskerDouble(w, h, isHorizontal) {
    let hLine = getSVGsymbol('line')(w),
        vLine = getSVGsymbol('vertical-line')(h),
        _replace = val => {
            return function() {
                let type = arguments[0][0];
                return type + val;
            };
        };

    if (isHorizontal) {
        let pattern = / (\d)+/g,
            hLine1 = hLine.replace(pattern, _replace(-h / 2)),
            hLine2 = hLine.replace(pattern, _replace(h / 2));

        return `${vLine} ${hLine1} ${hLine2}`;
    } else {
        let pattern = /M(\d)+|L(\d)+/g,
            vLine1 = vLine.replace(pattern, _replace(-w / 2)),
            vLine2 = vLine.replace(pattern, _replace(w / 2));

        return `${hLine} ${vLine1} ${vLine2}`;
    }
}

export function getSegmentsForWhisker(size, x, y, h, axisrotated) {
    if (axisrotated) {
        let vLine1 = getSegmentsForSymbol('vertical-line', size, y - h / 2, x),
            hLine = getSegmentsForSymbol('line', h, y, x);
        let vLine2 = getSegmentsForSymbol('vertical-line', size, y + h / 2, x);
        return [vLine1, hLine, vLine2];
    } else {
        let hLine1 = getSegmentsForSymbol('line', size, x, y - h),
            vLine = getSegmentsForSymbol('vertical-line', h, x, y);
        let hLine2 = getSegmentsForSymbol('line', size, x, y + h);
        return [hLine1, vLine, hLine2];
    }
}
